import styles from './styles.module.scss'; // Assuming the same SCSS file
import Image from 'next/image';
import { useRouter } from 'next/router';

export default function DangKy() {
  const router = useRouter();

  const handleLoginClick = () => {
    router.push('/DangNhap');
  };

  return (
    <div className={styles["outside-container"]}>
      <div className={styles["login-container"]}>
        <h1>Đăng Ký</h1>

        {/* Social Login (Facebook and Google) */}
        <div className={styles["social-buttons"]}>
          <button className={styles["facebook-button"]}>
            <Image
              src="/Facebook.svg"
              alt="Facebook Login"
              width={32}
              height={32}
            />
            <span>Tiếp tục với Facebook</span>
          </button>
          <button className={styles["google-button"]}>
            <Image
              src="/Google.svg"
              alt="Google Login"
              width={32}
              height={32}
            />
            <span>Đăng nhập với Google</span>
          </button>
        </div>
        <div className={styles["separator"]}>
          <span>Hoặc</span>
        </div>

        <form action="#" method="post" className={styles["login-form"]}>
          {/* Tài Khoản: Họ Tên, SĐT, GMAIL */}
          <div className={styles["form-group"]}>
            <input type="text" id="fullName" name="fullName" placeholder=" " />
            <label htmlFor="fullName">Họ Tên</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="tel" id="phone" name="phone" placeholder=" " />
            <label htmlFor="phone">SĐT</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="email" id="email" name="email" placeholder=" " />
            <label htmlFor="email">GMAIL</label>
          </div>

          {/* Tài Khoản Mật Khẩu */}
          <div className={styles["form-group"]}>
            <input type="text" id="username" name="username" placeholder=" " />
            <label htmlFor="username">Tài Khoản</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="password" id="password" name="password" placeholder=" " />
            <label htmlFor="password">Mật Khẩu</label>
          </div>

          {/* Mã Giới Thiệu */}
          <div className={styles["form-group"]}>
            <input type="text" id="referralCode" name="referralCode" placeholder=" " />
            <label htmlFor="referralCode">Mã Giới Thiệu</label>
          </div>

          {/* Phần Thông Tin: Tỉnh, Huyện, Xã, Ấp */}
          <div className={styles["form-group"]}>
            <input type="text" id="tinh" name="tinh" placeholder=" " />
            <label htmlFor="tinh">Tỉnh</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="text" id="huyen" name="huyen" placeholder=" " />
            <label htmlFor="huyen">Huyện</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="text" id="xa" name="xa" placeholder=" " />
            <label htmlFor="xa">Xã</label>
          </div>
          <div className={styles["form-group"]}>
            <input type="text" id="ap" name="ap" placeholder=" " />
            <label htmlFor="ap">Ấp</label>
          </div>

          <div className={styles["button-group"]}>
            <button type="submit" className={styles["register-button"]}>
              Đăng Ký
            </button>
          </div>
        </form>
      

      
        <div className={styles["links"]}>
            <button onClick={handleLoginClick}>Đăng Nhập</button>
             <a href="#">Quên mật khẩu?</a>
          </div>
      </div>
    </div>
  );
}